ALTER TABLE alcada_aprovacao DROP COLUMN IF EXISTS perfil, DROP COLUMN IF EXISTS valor_minimo, DROP COLUMN IF EXISTS valor_maximo, DROP COLUMN IF EXISTS nivel; ALTER TABLE alcada_aprovacao ADD COLUMN IF NOT EXISTS tipo_processo INT, ADD COLUMN IF NOT EXISTS controle_por_nivel BOOLEAN DEFAULT false, ADD COLUMN IF NOT EXISTS criado_em TIMESTAMP DEFAULT now(); CREATE TABLE IF NOT EXISTS alcada_participante (id TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, id_alcada TEXT NOT NULL REFERENCES alcada_aprovacao(id), id_usuario TEXT NOT NULL REFERENCES usuario(id), id_substituto TEXT REFERENCES usuario(id), nivel INT NOT NULL, valor_minimo DECIMAL(15,2), valor_maximo DECIMAL(15,2), notifica_email BOOLEAN DEFAULT true, notifica_tela BOOLEAN DEFAULT true, ativo BOOLEAN DEFAULT true, criado_em TIMESTAMP DEFAULT now());